export type CreatePaymentLinkData = {
    body: {
        /**
         * Charge amount in the smallest currency unit (e.g. cents for USD). Range 1–99,999,999.
         */
        amount_cents: number;
        /**
         * ISO 4217 three-letter currency code (e.g. "usd").
         */
        currency: string;
        /**
         * Product description shown on the Stripe Checkout page.
         */
        description?: string;
        /**
         * Stripe Connect account ID (format: acct_…). When present the session runs as a Direct Charge: Stripe charges the buyer via the merchant account; Oriva collects a 10% application fee. When absent the session falls back to Separate Transfers: Oriva charges on the platform account and distributes via the REA payout cron.
         */
        merchant_connect_account_id?: string;
        /**
         * REA manifest UUID for skill royalty attribution.
         */
        oriva_manifest_id?: string;
        /**
         * Unique invocation UUID for analytics and deduplication.
         */
        oriva_invocation_id?: string;
        /**
         * URL the buyer is redirected to after a successful payment. Must use https://.
         */
        success_url: string;
        /**
         * URL the buyer is redirected to if they abandon the checkout. Must use https://.
         */
        cancel_url: string;
        /**
         * Arbitrary key-value pairs forwarded to the Stripe Checkout Session metadata.
         */
        metadata?: {
            [key: string]: unknown;
        };
    };
    path?: never;
    query?: never;
    url: '/api/v1/payments/payment-links';
};

export type CreatePaymentLinkErrors = {
    /**
     * Validation error — missing required field or invalid format
     */
    400: unknown;
    /**
     * Missing or invalid API key
     */
    401: unknown;
    /**
     * Caller does not have a registered REA agent record. Register as a skill author at oriva.io/settings/developer before using this endpoint.
     */
    403: unknown;
    /**
     * Internal server error
     */
    500: unknown;
    /**
     * Stripe API error — details in response body
     */
    502: unknown;
};

export type CreatePaymentLinkResponses = {
    /**
     * Checkout Session created. Redirect the buyer to `data.url`.
     */
    200: PaymentLink;
};

export type CreatePaymentLinkResponse = CreatePaymentLinkResponses[keyof CreatePaymentLinkResponses];
